// Lightweight re-export of ControlType enum and related types without pulling in
// the full framer.js runtime (360KB + framer-chunks). Files like exporter.ts and
// typescript.ts only need these types/enum, not the entire Framer runtime.
// The enum values must stay in sync with framer.d.ts (auto-generated by scripts/download.ts).

export type { ControlDescription, PropertyControls } from './framer.js'

export enum ControlType {
    Boolean = 'boolean',
    Number = 'number',
    String = 'string',
    FusedNumber = 'fusednumber',
    Enum = 'enum',
    SegmentedEnum = 'segmentedenum',
    Color = 'color',
    Image = 'image',
    ResponsiveImage = 'responsiveimage',
    File = 'file',
    ComponentInstance = 'componentinstance',
    Slot = 'slot',
    Array = 'array',
    EventHandler = 'eventhandler',
    Transition = 'transition',
    BoxShadow = 'boxshadow',
    Link = 'link',
    Date = 'date',
    Object = 'object',
    Font = 'font',
    Border = 'border',
    Cursor = 'cursor',
    Padding = 'padding',
    BorderRadius = 'borderradius',
    Gap = 'gap',
    TrackingId = 'trackingid',
}
